import React from 'react';
import { NavLink, Route, Routes } from 'react-router-dom';
import HomePage from './pages/HomePage';
import AboutPage from './pages/AboutPage';
import CrmPage from './pages/CrmPage';
import CriteriaPage from './pages/CriteriaPage';
import RatingsPage from './pages/RatingsPage';
import ComparisonPage from './pages/ComparisonPage';
import EconomicPage from './pages/EconomicPage';

const navItems = [
  { path: '/', label: 'Home', end: true },
  { path: '/about', label: 'About' },
  { path: '/crm', label: 'CRM' },
  { path: '/criteria', label: 'Criteria' },
  { path: '/ratings', label: 'Ratings' },
  { path: '/comparison', label: 'Comparison' },
  { path: '/economic', label: 'Economics' }
];

const App = () => {
  return (
    <div className="app-shell">
      <aside className="sidebar">
        <div className="brand">
          <div className="brand-dot" />
          <div>
            <p className="brand-title">SaaS CRM</p>
            <p className="brand-subtitle">Decision Dashboard</p>
          </div>
        </div>

        <nav className="sidebar-nav">
          {navItems.map((item) => (
            <NavLink
              key={item.path}
              to={item.path}
              end={item.end}
              className={({ isActive }) =>
                `sidebar-link ${isActive ? 'active' : ''}`
              }
            >
              <span className="sidebar-link-dot" />
              {item.label}
            </NavLink>
          ))}
        </nav>
      </aside>

      <div className="main-area">
        <header className="topbar">
          <div>
            <p className="topbar-kicker">Flowbite-style UI</p>
            <h1 className="topbar-title">SaaS CRM Comparative Analyzer</h1>
          </div>
          <div className="topbar-user">
            <span className="status-pill">Online</span>
            <div className="user-avatar">A</div>
          </div>
        </header>

        <main className="content">
          <Routes>
            <Route path="/" element={<HomePage />} />
            <Route path="/about" element={<AboutPage />} />
            <Route path="/crm" element={<CrmPage />} />
            <Route path="/criteria" element={<CriteriaPage />} />
            <Route path="/ratings" element={<RatingsPage />} />
            <Route path="/comparison" element={<ComparisonPage />} />
            <Route path="/economic" element={<EconomicPage />} />
          </Routes>
        </main>
      </div>
    </div>
  );
};

export default App;
